const { S3Client, PutObjectCommand } = require('@aws-sdk/client-s3');
const crypto = require('crypto');

const s3Client = new S3Client({ region: process.env.AWS_REGION || 'us-east-1' });

const BUCKET_NAME = process.env.UPLOADS_BUCKET_NAME;
const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB
const ALLOWED_CONTENT_TYPES = [
  'image/jpeg',
  'image/png',
  'image/gif',
  'image/webp',
  'application/pdf',
  'text/plain',
  'text/csv'
];
const ALLOWED_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.gif', '.webp', '.pdf', '.txt', '.csv'];

exports.handler = async (event) => {
  const headers = {
    'Content-Type': 'application/json',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
    'Access-Control-Allow-Origin': process.env.ALLOWED_ORIGIN || 'https://yourdomain.com',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type'
  };

  try {
    if (event.httpMethod === 'OPTIONS') {
      return {
        statusCode: 200,
        headers,
        body: ''
      };
    }

    if (event.httpMethod !== 'POST') {
      return {
        statusCode: 405,
        headers,
        body: JSON.stringify({ error: 'Method not allowed' })
      };
    }

    if (!BUCKET_NAME) {
      console.error('UPLOADS_BUCKET_NAME environment variable not set');
      return {
        statusCode: 500,
        headers,
        body: JSON.stringify({ error: 'Server configuration error' })
      };
    }

    const contentType = event.headers['content-type'] || event.headers['Content-Type'] || '';
    
    if (!ALLOWED_CONTENT_TYPES.includes(contentType)) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ 
          error: 'Invalid content type',
          allowedTypes: ALLOWED_CONTENT_TYPES
        })
      };
    }

    let fileContent;
    if (event.isBase64Encoded) {
      fileContent = Buffer.from(event.body, 'base64');
    } else {
      fileContent = Buffer.from(event.body);
    }

    if (fileContent.length === 0) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: 'File content is empty' })
      };
    }

    if (fileContent.length > MAX_FILE_SIZE) {
      return {
        statusCode: 413,
        headers,
        body: JSON.stringify({ 
          error: 'File size exceeds maximum allowed size',
          maxSize: MAX_FILE_SIZE
        })
      };
    }

    const filename = event.headers['x-filename'] || event.headers['X-Filename'];
    if (!filename) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: 'Filename header (X-Filename) is required' })
      };
    }

    const sanitizedFilename = filename.replace(/[^a-zA-Z0-9._-]/g, '_').substring(0, 255);
    
    const fileExtension = sanitizedFilename.substring(sanitizedFilename.lastIndexOf('.')).toLowerCase();
    if (!ALLOWED_EXTENSIONS.includes(fileExtension)) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ 
          error: 'Invalid file extension',
          allowedExtensions: ALLOWED_EXTENSIONS
        })
      };
    }

    const timestamp = Date.now();
    const randomId = crypto.randomBytes(16).toString('hex');
    const s3Key = `uploads/${timestamp}-${randomId}-${sanitizedFilename}`;

    const uploadParams = {
      Bucket: BUCKET_NAME,
      Key: s3Key,
      Body: fileContent,
      ContentType: contentType,
      ServerSideEncryption: 'AES256',
      Metadata: {
        'upload-timestamp': timestamp.toString(),
        'original-filename': sanitizedFilename
      }
    };

    const command = new PutObjectCommand(uploadParams);
    await s3Client.send(command);

    return {
      statusCode: 201,
      headers,
      body: JSON.stringify({
        message: 'File uploaded successfully',
        fileId: randomId,
        filename: sanitizedFilename,
        size: fileContent.length,
        contentType: contentType
      })
    };

  } catch (error) {
    console.error('Upload error:', error.message);
    
    return {
      statusCode: 500,
      headers,
      body: JSON.stringify({ 
        error: 'Failed to upload file'
      })
    };
  }
};